    description: 'Научно-фантастический фильм о путешествиях во времени'
  },
};

// Данные для клипов
export const CLIPS = [
  { id: 1, movie_id: 1, title: 'Эдвард руки-ножницы', description: 'Трогательная история', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, poster_url: '/images/posters/edward.jpg' },
  { id: 2, movie_id: 2, title: 'Прислуга', description: 'Лучшие моменты', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, poster_url: '/images/posters/prisluga.jpg' },
  { id: 3, movie_id: 3, title: 'Красотка на всю голову', description: 'Смешные сцены', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, poster_url: '/images/posters/krasotka.jpg' },
  { id: 4, movie_id: 4, title: 'Достать ножи', description: 'Загадочное убийство', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, poster_url: '/images/posters/knives.jpg' },
  { id: 5, movie_id: 5, title: 'Оппенгеймер', description: 'Испытание бомбы', video_url: 'https://player.vimeo.com/video/76979871?autoplay=1', likes: 0, poster_url: '/images/posters/oppenheimer.jpg' }
];

export const getMovie = async (movieId) => {
  return MOVIES[movieId];
};

export const getClip = async (clipId) => {
  return CLIPS.find(c => c.id === clipId);
};

export const likeClip = async (clipId, liked) => {
  const clip = CLIPS.find(c => c.id === clipId);
  if (clip) {
    if (liked) {
      clip.likes += 1;
    } else {
      clip.likes = Math.max(0, clip.likes - 1);
    }
  }
  return { success: true, likes: clip?.likes || 0 };
};

export const saveMovie = async (movieId, email) => {
  const saved = localStorage.getItem(`saved_${email}`);
  let savedMovies = saved ? JSON.parse(saved) : [];

  if (savedMovies.includes(movieId)) {
    savedMovies = savedMovies.filter(id => id !== movieId);
    localStorage.setItem(`saved_${email}`, JSON.stringify(savedMovies));
    return { success: true, saved: false };
  } else {
    savedMovies.push(movieId);
    localStorage.setItem(`saved_${email}`, JSON.stringify(savedMovies));
    return { success: true, saved: true };
  }
};

export const checkSaved = async (movieId, email) => {
  const saved = localStorage.getItem(`saved_${email}`);
  const savedMovies = saved ? JSON.parse(saved) : [];
  return { saved: savedMovies.includes(movieId) };
};

export const registerUser = async (userData) => {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const existingUsers = localStorage.getItem('users');
      const users = existingUsers ? JSON.parse(existingUsers) : [];

      const userExists = users.some(u => u.email === userData.email);

      if (userExists) {
        reject({ error: 'Email уже зарегистрирован' });
      } else {
        const newUser = {
          username: userData.username,
          email: userData.email,
          registered_at: new Date().toISOString()
        };
        users.push(newUser);
        localStorage.setItem('users', JSON.stringify(users));

        resolve({
          success: true,
          message: 'Регистрация успешна',
          user: newUser
        });
      }
    }, 500);
  });
};

export default api;
